scwin.lobranCd;
scwin.vCurDate;
scwin.vstdYm;
scwin.v_workClsCd;
scwin.bOnPopUp;
scwin.insertCnt;
scwin.onpageload = function() {
    var rowIndex = ds_condition.insertRow();
    ds_condition.setRowPosition(rowIndex);

	scwin.lobranCd      = $c.gus.cfIsNull($c.data.getMemInfo("lobranCd")) ? "" : $c.data.getMemInfo("lobranCd");  // 물류 점소 코드
	scwin.vCurDate      = $c.date.getServerDateTime("yyyyMMdd");  // 서버를 기준으로 현재 날짜 반환
	scwin.vstdYm        = scwin.vCurDate.substring(0, 6)+"01";  // 작업월
    scwin.v_workClsCd   = ""; 
    scwin.bOnPopUp      = false;

    const codeOptions = [
        { grpCd : "OP316", compID : "acb_wrkPlClsCd" }, 

    ];
    $c.data.setCommonCode(codeOptions, scwin.setCommonCodeCallBack);
};

//-------------------------------------------------------------------------
// onUdcCompleted : UDC 완료. 그리는 시점 차이 보완. 
//-------------------------------------------------------------------------
scwin.onUdcCompleted = function() {
    $p.setTimeout(function() {


    }, {"delay":50});
};

scwin.setCommonCodeCallBack = async function(){
    acb_wrkPlClsCd.addItem("전체", "", "", 0);
    acb_wrkPlClsCd.setSelectedIndex(0);

    ds_combo1_search.set("sysCd", "BerthNonUsableEBC");
    ds_combo1_search.set("queryId", "retriveLobranCodeList");
    var rs = await $c.sbm.execute(sbm_lobranCd);
    if (rs.responseJSON.resultDataSet[0].Msg == "SUCC"){
        ds_combo1.setJSON(rs.responseJSON.GAUCE);
    };

	scwin.f_SetDefaultData();

};

// Default Data Setting
scwin.f_SetDefaultData = function () {
	ica_stdYm.setValue(scwin.vstdYm);	
	ica_endYm.setValue(scwin.vCurDate);
	acb_lobranCd.setValue(scwin.lobranCd);
	acb_lobranCd.focus();

    // $p.setTimeout(function() {
    //     acb_lobranCd.setValue("4AA");
    //     // ica_stdYm.setValue("20170401");
    //     // ica_endYm.setValue("20170405");
    //     ica_stdYm.setValue("20250701");
    //     ica_endYm.setValue("20250731");

    // }, {"delay":50});
};

// 상용직 근태현황 조회
scwin.f_Retrieve = async function () {
	// 검색조건 필수 입력 체크
  	if (!await $c.gus.cfValidate([acb_lobranCd, ica_stdYm])) {
  		return;
	}

	var dateCheck = "";
	var dateCheck = ica_stdYm.getValue();
	var enddate_Check = ica_endYm.getValue();

	var dateSearchCheck = dateCheck.slice(-2);
	var monthSearchCheck_std = dateCheck.substring(0, 6);
	var monthSearchCheck_end = enddate_Check.substring(0, 6);

	if (dateSearchCheck !== "01"){
		await $c.win.alert("작업시작일 1일부터 조회하실 수 있습니다.");
	}
	else if (monthSearchCheck_std != monthSearchCheck_end){
		await $c.win.alert("작업시작일과 작업 종료일의 연도와 월이 같아야합니다.");
	}
	else{
        scwin.insertCnt = 0;
        $c.sbm.execute(sbm_retrieve);

	}
};

// 검색영역 Field Clear함.
scwin.f_InitObjects = function () {
	$c.gus.cfInitObjects(tb_mainData);
	scwin.f_SetDefaultData();
};

scwin.btn_fieldClear_onclick = function (e) {
    scwin.f_InitObjects();
};

scwin.btn_retrieve_onclick = function (e) {
    scwin.f_Retrieve();
};

